import React, { useContext, useEffect, useCallback } from "react";

import { Paper, Grid, TextField, Avatar, Button,Typography } from "@mui/material";
import LockIcon from "@mui/icons-material/Lock";

import { useNavigate,Link } from "react-router-dom";
import { useFormik } from "formik";
import * as Yup from "yup";
import { APIs } from "../../Services/apis";
import { POST } from "../../Services/httpClient";
const SignUpSchema = Yup.object().shape({
  name: Yup.string(),
  email: Yup.string().email("invalid email address").required("Required"),
  password: Yup.string().required("Required"),
});

const Register = () => {
  let navigate = useNavigate();
  // const user = useContext(UserContext);
  const paperStyle = { padding: 20, width: 280, margin: "20px auto" };
  const avatarStyle = { backgroundColor: "#1bbd7e" };
  const btnstyle = { margin: "8px 0" };
  const user = localStorage.getItem("user");

  const handleOnSubmit = (values) => {
    SingupwithEmail(values);
  };

  const SingupwithEmail = async (values) => {
    var res = await POST(APIs.SIGNUP, {
      ...values,
    });
    if (res.status === 200) {
      if (res.data) {
        console.log(res);
        localStorage.setItem("user", JSON.stringify(res.data));
        navigate("/");
      }
    }
    if (res.status === 404) {
      navigate("/login");
    }
  };

  const formik = useFormik({
    initialValues: {
      email: "",
      password: "",
      name: "",
    },
    validationSchema: SignUpSchema,
    onSubmit: handleOnSubmit,
  });

  const setInputValue = useCallback(
    (key, value) =>
      formik.setValues({
        ...formik.values,
        [key]: value,
      }),
    [formik]
  );

  useEffect(() => {
    if (user) {
      return navigate("/");
    }
  }, [user]);

  return (
    <div>
      <div style={{ padding: 30 }}>
        <Grid>
          <Paper elevation={10} style={paperStyle}>
            <Grid align="center">
              <Avatar style={avatarStyle}>
                <LockIcon />
              </Avatar>
              <h2>Sign Up</h2>
            </Grid>
            <form onSubmit={formik.handleSubmit}>
              <TextField
                label="Name"
                placeholder="Enter Name"
                fullWidth
                value={formik.values.name}
                onChange={(e) => setInputValue("name", e.target.value)}
              />
              <TextField
                label="Email"
                placeholder="Enter Email"
                type="email"
                fullWidth
                required
                style={{ marginTop: 10 }}
                value={formik.values.email}
                onChange={(e) => setInputValue("email", e.target.value)}
              />
              <small>{formik.errors.email}</small>
              <TextField
                label="Password"
                placeholder="Enter password"
                type="password"
                fullWidth
                required
                style={{ marginTop: 10 }}
                value={formik.values.password}
                onChange={(e) => setInputValue("password", e.target.value)}
              />
              <small>{formik.errors.password}</small>
              <Button
                type="submit"
                color="primary"
                variant="contained"
                style={btnstyle}
                fullWidth
                disabled={!formik.isValid}
              >
                Sign Up
              </Button>
              
            </form>
            <Typography> Already Have Account ?<Link to="/login">Login</Link></Typography>
          </Paper>
        </Grid>
      </div>
    </div>
  );
};

export default Register;
